def solve(*args):
    # Assuming args contains the necessary inputs for the scoring system
    if not args or len(args) < 2:
        return None

    scores = []
    for arg in args:
        try:
            score = int(arg)
            if score < 0:
                return None
            scores.append(score)
        except ValueError:
            return None

    total_score = sum(scores)
    return total_score
